def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        if usage_ratio > 3:
            power_usage = np.power(usage_ratio, 1.3)
            priority += 4000 * power_usage
            if capacity > 7:
                priority += 150 * np.log1p(capacity) + np.sqrt(capacity) * 20
            else:
                priority -= 25 * usage_ratio * np.sin(usage_ratio)
            for p in range(1, 4):
                priority += (-1)**p * np.cos(capacity * p) * 30 / p
        elif 2 < usage_ratio <= 3:
            delta = usage_ratio - 2
            priority += 2000 * delta ** 2 + 120 * (1 - delta)
            for q in range(1, 6):
                sin_val = np.sin(usage_ratio * np.pi * q)
                priority += ((-1) ** q) * sin_val * 12 / (q + 1)
            if capacity % 2 < 0.4:
                priority += 25 * np.sin(capacity * 2)
        elif 1 < usage_ratio <= 2:
            try:
                log_val = np.log1p(-usage_ratio / 3 + 1e-12)
                priority += (-log_val) ** 3 * 18
            except FloatingPointError:
                priority += 200
            for j in range(1, 10):
                pow_val = usage_ratio ** j
                if pow_val < 0.25:
                    priority += pow_val * 20 / j
                    if j % 4 == 0:
                        priority += 3 * j
                else:
                    priority += (1 - pow_val) * 15 / (j + 2)
                    if j == 7 and usage_ratio > 1.8:
                        priority += 10
            if capacity % 2.2 < 0.5:
                priority += 30 * np.cos(capacity * 4)
        elif 0.3 < usage_ratio <= 1:
            priority += 150 * (1 - usage_ratio)
            for x in range(1, 7):
                ratio_pow = usage_ratio ** x
                tan_val = np.tan(ratio_pow * np.pi / 5)
                priority += (tan_val - 0.3) * 10 / x
                if usage_ratio < 0.12 * x:
                    priority -= 6 * x
            if capacity < 0.04:
                priority += np.sqrt(capacity) * 250
            elif capacity < 0.6:
                priority += np.log1p(capacity * 15) * 30
            else:
                priority += (capacity % 4) * 20
        else:
            priority += 50 * (1 - usage_ratio)**2
            for w in range(1, 8):
                ratio_pow = usage_ratio ** w
                if ratio_pow < 0.4:
                    priority += ratio_pow * 18 / w
                else:
                    priority += (1 - ratio_pow) * 11 / (w + 1)
                    if w == 6 and usage_ratio > 0.7:
                        priority += 12
            if capacity < 0.2:
                priority += 60 * np.exp(-capacity*10)
            elif capacity < 0.7:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 5) * 22
        if capacity < 0.15:
            priority += 60
            if usage_ratio > 0.85:
                priority += 70
            elif usage_ratio < 0.2:
                priority -= 40
                for r in range(1, 5):
                    priority -= r * np.exp(-usage_ratio * 15)
        elif capacity < 0.9:
            priority += 30
            if usage_ratio > 0.9:
                priority += 50
            elif usage_ratio < 0.35:
                priority -= 25
        else:
            if usage_ratio < 0.25:
                priority -= 30
            elif usage_ratio > 0.9:
                priority += 80
            else:
                priority += 20
        proximity_score = 0
        cap_mult_1000 = int(capacity * 1000)
        cap_mult_400 = int(capacity * 400)
        cap_mult_150 = int(capacity * 150)
        usage_mult_1000 = int(usage_ratio * 1000)
        if cap_mult_1000 % 17 == 0:
            proximity_score += 15
        if cap_mult_400 % 19 == 0:
            proximity_score -= 10
        if cap_mult_150 % 7 == 0:
            proximity_score += 12
        for k in range(1, 7):
            diff = abs(usage_ratio - k / 7)
            if diff < 0.035:
                proximity_score += 20 / k
            elif diff < 0.09:
                proximity_score += 10 / k
            else:
                proximity_score -= 3 / k
        for m in range(1, 6):
            mod_check = cap_mult_1000 % (m + 7)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 1:
                proximity_score -= m * 3
        for n in range(1, 4):
            mod_check = usage_mult_1000 % (n + 5)
            if mod_check == 0:
                proximity_score += 8 * n
            elif mod_check == 1:
                proximity_score -= 6 * n
        priority += proximity_score
        if usage_ratio < 0.015:
            for s in range(1, 6):
                priority -= s * 7
        elif usage_ratio > 0.97:
            for t in range(1, 6):
                priority += t * 8
        if capacity > 1.5:
            if capacity % 1 < 0.07:
                priority += 35
            if (cap_mult_1000 % 19 == 0) and (usage_ratio > 0.55):
                priority += 50
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        for final_adj in range(1, 4):
            if (int(capacity * 500) + int(usage_ratio * 500)) % (final_adj + 2) == 0:
                priority += final_adj * 10
            else:
                priority -= final_adj * 5
        priorities[i] = priority
    return priorities
